<template>

<!-- ==============================================
    ** Inner Banner **
    =================================================== -->
    <div class="inner-banner blog">
        <div class="container">
            <div class="row">
                <div class="col-sm-12">
                    <div class="content">
                        <h1> {{ Servicio.serv_nombre }} </h1>
                    </div>

                    <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
                <h5>
                  <a style="cursor: pointer" @click="clickBack()">SERVICIOS</a>
                </h5>
                <h3>{{ Servicio.serv_nombre }}</h3>
                </div>
            </div>
        </div>
    </div>

    <!-- ==============================================
    ** Blog Detail **
    =================================================== -->
    <div class="container blog-wrapper padding-lg">
        <div class="row">
            <!-- Start Left Column -->
            <div class="col-sm-8 blog-left">
                <ul class="blog-listing detail">
                    <li> 
                      <img
                  :src="url_api + '/Carrera/Servicios/' + Servicio.serv_imagen"
                  alt="img"
                  class="img-responsive"
                />
                 
                        <h2>{{ Servicio.serv_nombre }}</h2>
                        <ul class="post-detail">
                            <li><span class="icon-date-icon ico"></span><span class="bold">{{ dmy(Servicio.serv_registro) }}</span> </li>
                            <li>Contacto: <span class="bold">{{ Servicio.serv_nro_celular }}</span></li>
                            <li><span class="label">Servicio</span></li>
                        </ul>
                        <p class="left-aligned">Descripción del servicio:</p>
                        <p class=" left-aligned" v-html="Servicio.serv_descripcion"></p>
                    </li>
                </ul>
    
          
            </div>
            <!-- End Left Column -->

            <!-- Start Right Column -->
            <div class="col-sm-4">
                <div class="blog-right">
                    <!-- <div class="search-block clearfix">
                        <input name="Search" type="text" placeholder="Search">
                        <button class="search"><span class="icon-search-icon"></span></button>
                    </div> -->
                  </div>
                  <SidebarCustom></SidebarCustom>
                </div>
            <!-- End Right Column -->
        </div>
    </div>

</template>

<style scoped>
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>
import { mapState } from "vuex";
import SidebarCustom from "@/components/SidebarCustom.vue";
export default {
  name: "detalleServicio",
  data() {
    return {
      Servicio: {},
      errorGet: false,

      NUM_RESULTS: 3,
      pag: 1,
      pager: 0,
    };
  },
  components: {
    SidebarCustom,
  },
  computed: {
    ...mapState(["url_api"]),
  },
  methods: {
    async getServicioOne() {
      try {
        let res = await this.axios.get(
          "/api/Servicio/" + this.$route.params.idServ
        );
        this.Servicio = res.data.Descripcion;
        console.log(this.Servicio);
        this.pager = this.Servicio.imagen.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
        if (error.response.status == 500) {
          this.errorGet = true;
          this.$store.commit("loading");
        }
      }
    },
    dmy(fecha) {
      if (fecha != undefined) {
        const meses = [
          "enero",
          "febrero",
          "marzo",
          "abril",
          "mayo",
          "junio",
          "julio",
          "agosto",
          "septiembre",
          "octubre",
          "noviembre",
          "diciembre",
        ];
        let fechaCadena = fecha.substr(0, 10);
        let fechaArray = fechaCadena.split("-");
        return (
          fechaArray[2] +
          " de " +
          meses[parseInt(fechaArray[1]) - 1] +
          " de " +
          fechaArray[0]
        );
      }
    },
    clickBack() {
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getServicioOne();
  },
  created() {
    this.$store.commit("loadOn");
    this.getServicioOne();
  },
};
</script>